import sys
input = sys.stdin.readline

def solve():
    n, k = map(int, input().split())
    a = list(map(int, input().split()))

    INF = float('inf')
    # dp[j][c] = min d_j when j is the c-th selected element
    dp = [[INF] * (k + 1) for _ in range(n)]

    for j in range(n):
        pos = j + 1
        d = pos - a[j]
        if d >= 0:
            dp[j][1] = d

    for j in range(n):
        pos_j = j + 1
        d_j = pos_j - a[j]
        if d_j < 0:
            continue
        for prev in range(j):
            pos_prev = prev + 1
            d_prev = pos_prev - a[prev]
            if d_prev < 0:
                continue
            if dp[prev][1] == INF and 1 < k:
                pass
            # check constraints
            if d_j < d_prev:
                continue
            if d_j - d_prev > pos_j - pos_prev - 1:
                continue
            for c in range(1, k):
                if dp[prev][c] < INF:
                    if d_j < dp[j][c+1]:
                        dp[j][c+1] = d_j

    ans = INF
    for j in range(n):
        if dp[j][k] < INF:
            ans = min(ans, dp[j][k])

    print(-1 if ans == INF else ans)

t = int(input())
for _ in range(t):
    solve()
